datos.CSS:
/*--------------------------------------------------------------------------------
*							Todo
QCalendarWidget				Calendario
QCheckBox					Botón de check
QComboBox					Combobx
QDateEdit					Caja de edición de campo fecha en modo de edición fecha
QDateTime					Caja de visualización de campo tiempo: fecha y hora
QDateTimeEdit				Caja de edición de campo tiempo: fecha y hora
QDialog						Ventana en cuadro de diálogo
QDockWidget					Dock
QDoubleSpinBox				Caja de edición de campo numérico con botones arriba y abajo
QFrame						Marco
QGroupBox					Caja de grupo
QHeaderView					Cabecera de rejilla y árbol
QLabel						Etiqueta de texto
QLineEdit					Caja de edición de texto en una línea
QMainWindow					Ventana principal
QMenu						Menú contextual
QMenuBar					Barra de menú (Solo afecta a Windows)
QMessageBox					Ventana de mensaje
QNumberSpinBox				Caja de edición de campo numérico con botones arriba y abajo
QProgressBar				Barra de progreso
QPushButton					Botón
QRadioButton				Botón de radio
QScrollBar					Barra de scroll vertical y horizontal
QSlider						Deslizador
QSpinBox					Botones arriba y abajo
QSplitter					Separador móvil
QStatusBar					Barra de estado
QTableView					Detalle de la rejilla
QTabWidget					Separador de formularios mediante pestañas
QTextEdit					Caja de edición de texto multilínea
QTimeEdit					Caja de edición de hora
QTitanGrid					Rejilla avanzada
QToolBar					Barras de herramientas
QTooltip					Tooltip
QTreeWidget					Control árbol
QTreeView					Árbol visor de tablas y menú arbolado
QWidget#qt_calendar			Barra de navegación del calendario
VBoundFieldEdit				Caja de edición de campo puntero a maestro
VCContenedorNotificaciones	Contenedor de notificaciones
VCFootView					Pie de la rejilla
VCNotificacion				Tarjeta de notificación
VCPVControlCasillero		Casillero
VCPVControlFormulario		Formulario
VCPVControlMultiVista		Multivista
VDateLineEdit				Caja de edición de campo fecha en modo de edición alfanumérico
VFormulaEditBrowser			Caja de edición de fórmulas
VListBox					ListBox
VSwitch						Interruptor
MEN_APP						Menú general
VAG_IA						vAgente IA
SEL_INS						Selector de instancia
ASI_NAV						Asitente navegante
ASI_MOD_CAM					Asistente modificar campo
----------------------------------------------------------------------------------*/

/*--------------------------------------------------------------------------------
* - Todo
QFrame - Marco
--------------------------------------------------------------------------------*/
* {
	font-family: $fuente-familia;
	font-size: $fuente-size-defecto;
	margin: 0;
	padding: 0;
}

QFrame {
	background: $frame-fondo-color;
	border: $frame-borde-size solid $frame-borde-color;
}

/*--------------------------------------------------------------------------------
QCalendarWidget - Calendario
QWidget#qt_calendar - Barra de navegación del calendario
--------------------------------------------------------------------------------*/

QCalendarWidget {
	min-height: $calendar-alto-minimo;
	min-width: $calendar-ancho-minimo;
	qproperty-gridVisible: true;
	qproperty-navigationBarVisible: true;
}

QCalendarWidget QTableView {
	background-color: $calendar-fondo-color;
}

QCalendarWidget QTableView {
	background-color: $calendar-fondo-color;
	border: $calendar-dias-borde-size solid $calendar-dias-borde-color;
	min-height: $calendar-dias-alto-minimo;
	min-width: $calendar-dias-ancho-minimo;
}

QCalendarWidget QSpinBox {
	background-color: $calendar-fondo-color;
	color: $calendar-spinbox-texto-color;
	font-size: $calendar-spinbox-fuente-size;
	width: $calendar-spinbox-ancho;
}

QCalendarWidget QSpinBox::down-button {
	subcontrol-origin: border;
	subcontrol-position: bottom right;
	width: $calendar-boton-ancho;
}

QCalendarWidget QSpinBox::up-button {
	subcontrol-origin: border;
	subcontrol-position: top right;
	width: $calendar-boton-ancho;
}

QWidget#qt_calendar_navigationbar {
	background-color: $calendar-barra-fondo-color;
}

QWidget#qt_calendar_nextmonth {
	background: $calendar-fondo-color;
	border: $calendar-borde-size solid $calendar-borde-color;
	margin-right: $calendar-boton-mes-siguiente-margen;
	qproperty-icon: url("$sysCacheClientPath/DER.png");
}

QWidget#qt_calendar_prevmonth {
	background: $calendar-fondo-color;
	border: $calendar-borde-size solid $calendar-borde-color;
	margin-left: $calendar-boton-mes-anterior-margen;
	qproperty-icon: url("$sysCacheClientPath/IZQ.png");
}

QWidget#qt_calendar_monthbutton,
QWidget#qt_calendar_yearbutton {
	background: $calendar-fondo-color;
	border: $calendar-borde-size solid $calendar-borde-color;
	color: $calendar-texto-color;
}

/*--------------------------------------------------------------------------------
QCheckBox - Botón de check
--------------------------------------------------------------------------------*/

QCheckBox {
	background: $checkbox-fondo-color;
	border: $checkbox-borde-size solid $checkbox-borde-color;
	color: $checkbox-texto-color;
	height: $checkbox-alto;
	margin: $margen-sin;
	spacing: 0;
	text-decoration: none;
	outline: none;
}

QCheckBox:hover {
	border: $checkbox-borde-size solid $checkbox-borde-color-hover;
	color: $checkbox-texto-color-hover;
}

QCheckBox:focus {
	border: $checkbox-borde-size solid $checkbox-borde-color-focus;
	color: $checkbox-texto-color-focus;
}

QCheckBox:disabled {
	background: $checkbox-fondo-color;
	color: $control-texto-color-disabled;
	;
}

QCheckBox::indicator {
	margin-right: $control-componentes-espacio;
	position: left;
}

QCheckBox::indicator:unchecked {
	image: url("$sysCacheClientPathCHK_BTN_OFF.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:unchecked:hover {
	image: url("$sysCacheClientPathCHK_BTN_OFF_FOC.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:unchecked:focus {
	image: url("$sysCacheClientPathCHK_BTN_OFF_FOC.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:unchecked:pressed {
	image: url("$sysCacheClientPathCHK_BTN_OFF.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:unchecked:disabled {
	image: url("$sysCacheClientPathCHK_BTN_OFF_DES.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:checked {
	image: url("$sysCacheClientPathCHK_BTN_ON.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:checked:hover {
	image: url("$sysCacheClientPathCHK_BTN_ON_FOC.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:checked:focus {
	image: url("$sysCacheClientPathCHK_BTN_ON_FOC.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:checked:pressed {
	image: url("$sysCacheClientPathCHK_BTN_ON.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:checked:disabled {
	image: url("$sysCacheClientPathCHK_BTN_ON_DES.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:indeterminate:hover {
	image: url("$sysCacheClientPathCHK_BTN_OFF.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

QCheckBox::indicator:indeterminate:pressed {
	image: url("$sysCacheClientPathCHK_BTN_ON.png");
	width: $checkbox-icono-size;
	height: $checkbox-icono-size;
}

/*--------------------------------------------------------------------------------
QComboBox - Combobox
--------------------------------------------------------------------------------*/

QComboBox {
	background-color: $combobox-fondo-color;
	border-color: $combobox-borde-color;
	border-style: $combobox-borde-style;
	border-width: $combobox-borde-width;
	border-radius: $combobox-borde-radius;
	color: $combobox-texto-color;
	font-size: $combobox-fuente-size;
	height: $combobox-alto;
	padding-left: $combobox-padding-izquierda;
	padding-right: $combobox-padding-derecha;
	selection-background-color: $combobox-seleccionado-fondo-color;
	selection-color: $combobox-seleccionado-texto-color;
	width: $ancho-referencia;
}

QComboBox:hover {
	border-color: $combobox-borde-color-hover;
	border-width: $combobox-borde-width-hover;
}

QComboBox:focus {
	border-color: $combobox-borde-color-focus;
	border-width: $combobox-borde-width-focus;
}

QComboBox:disabled {
	background-color: $control-fondo-color-disabled;
	border-color: $combobox-borde-color-disabled;
	border-width: $combobox-borde-width-disabled;
	color: $control-texto-color-disabled;
}

QComboBox::drop-down {
	border: none;
	image: url($sysCacheClientPath/ABA.png);
	width: $combobox-icono-ancho;
}

QComboBox QAbstractItemView {
	background-color: $combobox-fondo-color;
	border: $combobox-seleccionado-borde-size solid $combobox-seleccionado-borde-color;
	padding: 12px;
	padding-left: 0px;

}

QComboBox::item {
	background-color: transparent;
	border: none;
	border-radius: $combobox-borde-radius;
	color: $combobox-seleccionado-texto-color;
	height: $combobox-item-alto;
	margin-top: 12px;
	margin-bottom: 3px;
	margin-left: 12px;
	padding: 0px;
}

QComboBox::item:selected {
	background-color: $combobox-seleccionado-fondo-color;
}

/*--------------------------------------------------------------------------------
Controles de edición QDateEdit, QDateTime, QDateTimeEdit, QDoubleSpinBox,
QNumberSpinBox, QSpinBox, QTimeEdit, VBoundFieldEdit, VDateLineEdit, VListBox
--------------------------------------------------------------------------------*/

QDateEdit,
VDateLineEdit,
QDateTime,
QDateTimeEdit,
QDoubleSpinBox,
QNumberSpinBox,
QSpinBox,
QTimeEdit,
VBoundFieldEdit,
VBoundFieldEditBrowser,
VFormulaEditBrowser,
VListBox {
	background-color: $control-fondo-color;
	border-color: $control-borde-color;
	border-style: $control-borde-style;
	border-width: $control-borde-width;
	border-radius: $control-borde-radius;
	color: $control-texto-color-edicion;
	font-size: $control-fuente-size;
	height: $control-alto;
	margin-right: $control-margen-derecha;
	padding-left: $control-padding-izquierda;
	padding-right: $control-padding-derecha;
	selection-background-color: $control-fondo-texto-color-seleccionado;
	selection-color: $control-texto-color-seleccionado;
	width: $ancho-referencia;
}

QDateEdit[readOnly="true"],
VDateLineEdit[readOnly="true"],
QDateTime[readOnly="true"],
QDateTimeEdit[readOnly="true"],
QDoubleSpinBox[readOnly="true"],
QNumberSpinBox[readOnly="true"],
QSpinBox[readOnly="true"],
QTimeEdit[readOnly="true"],
VBoundFieldEdit[readOnly="true"],
VBoundFieldEditBrowser[readOnly="true"],
VFormulaEditBrowser[readOnly="true"],
VListBox[readOnly="true"] {
	border: none;
	margin-right: 0px;
}

QDateEdit:hover,
VDateLineEdit:hover,
QDateTime:hover,
QDateTimeEdit:hover,
QDoubleSpinBox:hover,
QNumberSpinBox:hover,
QSpinBox:hover,
QTimeEdit:hover,
VBoundFieldEdit:hover,
VBoundFieldEditBrowser:hover,
VFormulaEditBrowser:hover,
VListBox:hover {
	border-color: $control-borde-color-hover;
	border-width: $control-borde-width-hover;
}

QDateEdit:hover[readOnly="true"],
VDateLineEdit:hover[readOnly="true"],
QDateTime:hover[readOnly="true"],
QDateTimeEdit:hover[readOnly="true"],
QDoubleSpinBox:hover[readOnly="true"],
QNumberSpinBox:hover[readOnly="true"],
QSpinBox:hover[readOnly="true"],
QTimeEdit:hover[readOnly="true"],
VBoundFieldEdit:hover[readOnly="true"],
VBoundFieldEditBrowser:hover[readOnly="true"],
VFormulaEditBrowser:hover[readOnly="true"],
VListBox:hover[readOnly="true"] {
	border: none;
}

QDateEdit:focus,
VDateLineEdit:focus,
QDateTime:focus,
QDateTimeEdit:focus,
QDoubleSpinBox:focus,
QNumberSpinBox:focus,
QSpinBox:focus,
QTimeEdit:focus,
VBoundFieldEdit:focus,
VBoundFieldEditBrowser:focus,
VFormulaEditBrowser:focus,
VListBox:focus {
	border-color: $control-borde-color-focus;
	border-width: $control-borde-width-focus;
}

QDateEdit:focus[readOnly="true"],
VDateLineEdit:focus[readOnly="true"],
QDateTime:focus[readOnly="true"],
QDateTimeEdit:focus[readOnly="true"],
QDoubleSpinBox:focus[readOnly="true"],
QNumberSpinBox:focus[readOnly="true"],
QSpinBox:focus[readOnly="true"],
QTimeEdit:focus[readOnly="true"],
VBoundFieldEdit:focus[readOnly="true"],
VBoundFieldEditBrowser:focus[readOnly="true"],
VFormulaEditBrowser:focus[readOnly="true"],
VListBox:focus[readOnly="true"] {
	border: none;
}

QDateEdit:disabled,
VDateLineEdit:disabled,
QDateTime:disabled,
QDateTimeEdit:disabled,
QDoubleSpinBox:disabled,
QNumberSpinBox:disabled,
QSpinBox:disabled,
QTimeEdit:disabled,
VBoundFieldEdit:disabled,
VBoundFieldEditBrowser:disabled,
VFormulaEditBrowser:disabled,
VListBox:disabled {
	background-color: $control-fondo-color-disabled;
	border-color: $control-borde-color-disabled;
	border-width: $control-borde-width-disabled;
	color: $control-texto-color;
}

QDateEdit::up-button,
VDateLineEdit::up-button,
QDateTime::up-button,
QDateTimeEdit::up-button,
QTimeEdit::up-button,
VBoundFieldEdit::up-button,
VBoundFieldEditBrowser::up-button,
VFormulaEditBrowser::up-button {
	border: none;
	image: url($sysCacheClientPath/ARR.png);
	width: $combobox-icono-ancho;
}

QDateEdit::down-button,
VDateLineEdit::down-button,
QDateTime::down-button,
QDateTimeEdit::down-button,
QTimeEdit::down-button,
VBoundFieldEdit::down-button,
VBoundFieldEditBrowser::down-button,
VFormulaEditBrowser::down-button {
	border: none;
	image: url($sysCacheClientPath/ABA.png);
	width: $combobox-icono-ancho;
}

QDateEdit::drop-down,
VDateLineEdit::drop-down,
QDateTime::drop-down,
QDateTimeEdit::drop-down,
VBoundFieldEdit::drop-down,
VBoundFieldEditBrowser::drop-down,
VFormulaEditBrowser::drop-down,
QTimeEdit::drop-down {
	border: none;
	image: url($sysCacheClientPath/ABA.png);
	width: $combobox-icono-ancho;
}

QNumberSpinBox,
QDoubleSpinBox,
QSpinBox,
VBoundFieldEdit,
VBoundFieldEditBrowser,
VFormulaEditBrowser {
	padding-right: $control-botones-padding-derecha;
}

QNumberSpinBox:up-button,
QDoubleSpinBox:up-button,
QSpinBox:up-button {
	border: 0px;
	image: url($sysCacheClientPath/ARR.png);
}

QNumberSpinBox:down-button,
QDoubleSpinBox:down-button,
QSpinBox:down-button {
	border: 0px;
	image: url($sysCacheClientPath/ABA.png);
}

/*--------------------------------------------------------------------------------
QDialog - Ventana en cuadro de diálogo
--------------------------------------------------------------------------------*/

QDialog {
	background: $dialog-fondo-color;
	border: $dialog-borde-size solid $dialog-borde-color;
}

/*--------------------------------------------------------------------------------
QDockWidget - Dock
--------------------------------------------------------------------------------*/

QDockWidget {
	background: $dock-fondo-color;
	color: $dock-color;
	font-size: $dock-fuente-size;
	qproperty-titleBarVisible: $dock-titulo-visible;
}

/* Título del dock (no auto-ocultable) */
QDockWidget::title {
	background: $dock-fondo-color;
	color: $dock-texto-color;
	font-size: $dock-titulo-fuente-size;
	margin: 0px;
	padding: 0px;
	text-align: left;
}

/* Título del dock (auto-ocultable) */
QDockWidget QWidget::title {
	background: $dock-fondo-color;
	color: $dock-texto-color;
	font-size: $dock-titulo-fuente-size;
}

/* Botones de la barra de título del dock (auto-ocultable) */
QDockWidget QWidget#title QToolButton#autohide,
QDockWidget QWidget#title QToolButton#close,
QDockWidget QWidget#title QToolButton#float {
	background-color: $dock-titulo-boton-fondo;
	border: $dock-titulo-boton-borde-size solid $dock-titulo-boton-borde-color;
	qproperty-iconSize: $dock-titulo-boton-icono-size;
}

/* Botones de la barra de título del dock (no auto-ocultable) */
QDockWidget::close-button,
QDockWidget::float-button {
	background-color: $dock-titulo-boton-fondo;
	image: none;
	position: absolute;
	subcontrol-origin: margin;
	subcontrol-position: top right;
	top: 0px;
	left: 0px;
	bottom: 0px;
	width: 0px;
}

/*--------------------------------------------------------------------------------
QGroupBox - Caja de grupo
--------------------------------------------------------------------------------*/

QGroupBox {
	background-color: $caja-fondo-color;
	border: $borde-size solid $control-borde-color;
	border-radius: $caja-borde-radius;
	color: $caja-titulo-color;
	font-size: $caja-fuente-size;
	font-weight: $caja-fuente-peso;
	margin-top: $caja-margen-top;
	padding: $caja-padding;
}

QGroupBox::title {
	color: $caja-titulo-color;
	padding-top: $caja-titulo-padding-top;
	padding-left: $caja-titulo-padding-izquierdo;
	subcontrol-origin: margin;
}

QGroupBox#CAJ_FLT {
	background-color: $caja-filtro-fondo-color;
	border: $caja-filtro-borde-size solid $caja-filtro-borde-color;
	border-radius: $caja-filtro-borde-radius;
	min-height: $caja-filtro-alto;
}

/* BOTÓN FILTRO Y LIMPIAR FILTRO */
QGroupBox#CAJ_FLT QPushButton#BTN_ACE {
	min-width: $boton-filtro-ancho;
}

QGroupBox#CAJ_FLT QPushButton#BTN_FLT_LIM {
	background-color: $boton-filtro-limpiar-fondo-color;
	min-width: $boton-filtro-limpiar-ancho;
}

/*--------------------------------------------------------------------------------
QLabel - Etiqueta de texto
--------------------------------------------------------------------------------*/

QLabel {
	background-color: $label-fondo-color;
	color: $label-color;
	margin: 0px;
	margin-right: $control-padding-derecha;
	padding: 0px;
}

/* Títulos de los formularios y menús */

QLabel#TXT_TIT {
	color: $label-titulo-color;
	font-size: $label-titulo-fuente-size;
	font-weight: $label-titulo-peso;
}

/*--------------------------------------------------------------------------------
QLineEdit - Caja de edición de texto en una línea
--------------------------------------------------------------------------------*/

QLineEdit {
	background-color: $control-fondo-color;
	border-color: $control-borde-color;
	border-style: $control-borde-style;
	border-width: $control-borde-width;
	border-radius: $control-borde-radius;
	color: $control-texto-color-edicion;
	font-size: $control-fuente-size;
	height: $control-alto;
	padding-left: $lineedit-padding-izquierda;
	selection-background-color: $control-fondo-texto-color-seleccionado;
	selection-color: $control-texto-color-seleccionado;
}

QLineEdit[readOnly="true"] {
	border: none;
}

QLineEdit:hover {
	border-color: $control-borde-color-hover;
	border-width: $control-borde-width-hover;
}

QLineEdit:focus {
	border-color: $control-borde-color-focus;
	border-width: $control-borde-width-focus;
	padding-left: $lineedit-padding-izquierda-resaltado;
}

QLineEdit:disabled {
	background-color: $control-fondo-color-disabled;
	border-color: $control-borde-color-disabled;
	border-width: $control-borde-width-disabled;
	color: $control-texto-color;
}

/* Textos a buscar en menús */

QLineEdit#TXT_BUS {
	qproperty-placeholderText: 'Texto a buscar';
}

/* Formular alta contacto: nombre fiscal y nombre */

QLineEdit#NAME_CON {
	qproperty-placeholderText: 'Nombre contacto';
	qproperty-text: 'Nombre contacto';
}

/*--------------------------------------------------------------------------------
QMainWindow - Ventana principal
--------------------------------------------------------------------------------*/

QMainWindow {
	background: $mainwindow-fondo-color;
	border: 0px;
}

QMainWindow::separator {
	background: $mainwindow-separador-fondo-color;
	border-left: $borde-size solid $mainwindow-separador-borde-color;
	border-right: $borde-size solid $mainwindow-separador-borde-color;
	height: $mainwindow-separador-ancho;
	width: $mainwindow-separador-ancho;
}

QMainWindow::separator:hover {
	background: $mainwindow-separador-fondo-color-hover;
}

/*--------------------------------------------------------------------------------
QMenu - Menú contextual
--------------------------------------------------------------------------------*/

QMenu {
	background-color: $menu-fondo-color;
	border: $menu-borde-size solid $menu-borde-color;
	color: $menu-texto-color;
	margin: $menu-margin;
	padding: $menu-padding;
}

QMenu::icon {
	background: transparent;
	qproperty-iconSize: $menu-icono-size;
}

QMenu::item {
	border: $menu-borde-size solid $menu-item-borde-color;
	border-radius: $menu-borde-radius;
	height: $menu-item-alto;
	padding-left: $menu-item-padding-izquierda;
	padding-right: $menu-item-padding-derecha;
}

QMenu::item:disabled {
	color: $menu-texto-color-disabled;
}

QMenu::item:hover {
	color: $menu-texto-color-hover;
}

QMenu::item:selected {
	background-color: $menu-item-seleccionado-fondo-color;
	color: $menu-item-seleccionado-texto-color;
}

QMenu::separator {
	background-color: $menu-separador-fondo-color;
	height: $menu-separador-size;
	margin-bottom: $menu-separador-margen;
	margin-top: $menu-separador-margen;
}

QMenu::indicator {
	height: $menu-indicador-size;
	width: $menu-indicador-size;
}

QMenu::right-arrow {
	height: $menu-arrow-size;
	image: url("$sysCacheClientPath/SIG.png");
	width: $menu-arrow-size;
}

QMenu::left-arrow {
	height: $menu-arrow-size;
	image: url("$sysCacheClientPath/ANT.png");
	width: $menu-arrow-size;
}

/*--------------------------------------------------------------------------------
QMenuBar - Barra de menú (Solo afecta a Windows)
--------------------------------------------------------------------------------*/

QMenuBar {
	background-color: $menubar-fondo-color;
	border-bottom: $menubar-borde-size solid $menubar-borde-color;
	color: $menubar-texto-color;
}

QMenuBar::item {
	background: transparent;
	padding: $menubar-item-padding;
}

QMenuBar::item:selected {
	background-color: $menubar-item-fondo-color-seleccionado;
	color: $menubar-item-texto-color-seleccionado;
}

QMenuBar::item:hover {
	background-color: $menubar-item-fondo-color-hover;
	color: $menubar-item-texto-color-hover;
}

/*--------------------------------------------------------------------------------
QMessageBox - Ventana de mensaje
--------------------------------------------------------------------------------*/

QMessageBox {
	background-color: $messagebox-fondo-color;
	border: $messagebox-borde-size solid $messagebox-borde-color;
	color: $messagebox-texto-color;
	qproperty-icon: 'NoIcon';
	/* 0=NoIcon, 1=Information, 2=Warning, 3=Critical, 4=Question */
}

QMessageBox QPushButton {
	min-width: $messagebox-boton-ancho;
}

/*--------------------------------------------------------------------------------
QProgressBar - Barra de progreso
--------------------------------------------------------------------------------*/

QProgressBar {
	background-color: $progressbar-fondo-color;
	border: $progressbar-borde-size solid $progressbar-borde-color;
	border-radius: $progressbar-borde-radius;
	color: $progressbar-texto-color;
	font-size: $progressbar-fuente-size;
	height: $progressbar-alto;
	text-align: $progressbar-texto-alineacion;
}

QProgressBar::chunk {
	background-color: $progressbar-chunk-fondo-color;
	border-radius: $progressbar-chunk-borde-radius;
}

/*--------------------------------------------------------------------------------
QPushButton - Botón
--------------------------------------------------------------------------------*/

QPushButton {
	background-color: $boton-fondo-color;
	border: $boton-borde-size solid $boton-borde-color;
	border-radius: $boton-borde-radius;
	color: $boton-texto-color;
	font-size: $boton-fuente-size;
	font-weight: $boton-texto-peso;
	height: $boton-alto;
	min-width: $boton-ancho;
	padding-left: 18px;
	padding-right: 18px;
	outline: 0;
	text-align: $boton-texto-alineacion;
	text-transform: $boton-texto-transformacion;
	qproperty-iconSize: $boton-icono-size;
}

QPushButton:hover {
	background-color: $boton-fondo-color-hover;
	border: $boton-borde-size-hover solid $boton-borde-color-hover;
	color: $boton-texto-color-hover;
}

QPushButton:focus {
	background-color: $boton-fondo-color-focus;
	border: $boton-borde-size-focus solid $boton-borde-color-focus;
	color: $boton-texto-color-focus;
}

QPushButton:pressed {
	background-color: $boton-fondo-color-pressed;
	border: $boton-borde-size-pressed solid $boton-borde-color-pressed;
	color: $boton-texto-color-pressed;
}

QPushButton:disabled {
	background-color: $boton-fondo-color-disabled;
	border: $boton-borde-size solid $boton-borde-color-disabled;
	color: $boton-texto-color-disabled;
}

QPushButton::menu-indicator {
	image: none;
	width: $icono-size-sin;
}

/* Botón aceptar */

QPushButton#BTN_ACE,
QPushButton#BTN_ALT {
	background-color: $boton-cta-fondo-color-defecto;
	border: $boton-borde-size solid $boton-cta-borde-color;
	color: $boton-cta-texto-color-defecto;
}

QPushButton#BTN_ALT {
	min-width: $boton-alt-ancho-minimo;
}

QPushButton:hover#BTN_ACE,
QPushButton:hover#BTN_ALT {
	background-color: $boton-cta-fondo-color-hover;
	border: none;
	color: $boton-cta-texto-color-hover;
}

QPushButton:focus#BTN_ACE,
QPushButton:focus#BTN_ALT {
	background-color: $boton-cta-fondo-color-focus;
	border: $boton-borde-size-seleccionado solid $boton-cta-borde-color-focus;
	color: $boton-cta-texto-color-focus;
}

QPushButton:pressed#BTN_ACE,
QPushButton:pressed#BTN_ALT {
	background-color: $boton-cta-fondo-color-pressed;
	border: $boton-borde-size solid $boton-cta-borde-color-pressed;
	color: $boton-cta-texto-color-pressed;
}

QPushButton:disabled#BTN_ACE,
QPushButton:disabled#BTN_ALT {
	background-color: $boton-fondo-color-disabled;
	border: $boton-borde-size solid $boton-borde-color-disabled;
	color: $boton-texto-color-disabled;
}

/* Botón advertencia */

QPushButton#BTN_ADV {
	background-color: $boton-adv-fondo-color-defecto;
	border: $boton-borde-size solid $boton-adv-borde-color-defecto;
	color: $boton-adv-texto-color-defecto;
}

QPushButton:hover#BTN_ADV {
	background-color: $boton-adv-fondo-color-hover;
	border: $borde-size-seleccionado solid $boton-adv-borde-color-hover;
	color: $boton-adv-texto-color-hover;
}

QPushButton:focus#BTN_ADV {
	background-color: $boton-adv-fondo-color-focus;
	border: $borde-size-seleccionado solid $boton-adv-borde-color-focus;
	color: $boton-adv-texto-color-focus;
}

QPushButton:pressed#BTN_ADV {
	background-color: $boton-adv-fondo-color-pressed;
	border: $boton-borde-size solid $boton-adv-borde-color-pressed;
	color: $boton-adv-texto-color-defecto;
}

QPushButton:disabled#BTN_ADV {
	background-color: $boton-fondo-color-disabled;
	border: $boton-borde-size solid $boton-borde-color-disabled;
	color: $boton-texto-color-disabled;
}

