/* Botón ampliar, ayuda, buscar, filtro desactivado y activado, menú y reducir */

QPushButton#BTN_AMP,
QPushButton#BTN_AYU,
QPushButton#BTN_BUS,
QPushButton#BTN_FLT_OFF,
QPushButton#BTN_FLT_ON,
QPushButton#BTN_MEN,
QPushButton#BTN_RED {
	border-radius: $boton-icono-borde-radius;
	min-height: $boton-icono-alto;
	min-width: $boton-icono-ancho;
	padding-left: 0px;
	padding-right: 0px;
	qproperty-iconSize: $boton-icono-size;
}

/* Botón oculto avanza control y cancelar */

QPushButton#BTN_AVA_CTL {
	border: none;
	max-height: 0px;
	max-width: 0px;
}

/*--------------------------------------------------------------------------------
QRadioButton - Botón de radio
--------------------------------------------------------------------------------*/

QRadioButton {
	background: $radiobutton-fondo-color;
	border: $radiobutton-borde-size solid $radiobutton-borde-color;
	color: $radiobutton-texto-color;
	height: $radiobutton-alto;
	margin: $margen-sin;
	spacing: 0;
	text-decoration: none;
	outline: none;
}

QRadioButton:hover {
	border: $radiobutton-borde-size solid $radiobutton-borde-color-hover;
	color: $radiobutton-texto-color-hover;
}

QRadioButton:focus {
	border: $radiobutton-borde-size solid $radiobutton-borde-color-focus;
	color: $radiobutton-texto-color-focus;
}

QRadioButton:disabled {
	background: $radiobutton-fondo-color;
	color: $control-texto-color-disabled;
}

QRadioButton::indicator {
	margin-right: $control-componentes-espacio;
	position: left;
}

QRadioButton::indicator:unchecked {
	image: url("$sysCacheClientPathRAD_BTN_OFF.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:unchecked:hover {
	image: url("$sysCacheClientPathRAD_BTN_OFF_FOC.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:unchecked:focus {
	image: url("$sysCacheClientPathRAD_BTN_OFF_FOC.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:unchecked:pressed {
	image: url("$sysCacheClientPathRAD_BTN_OFF.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:unchecked:disabled {
	image: url("$sysCacheClientPathRAD_BTN_OFF_DES.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:checked {
	image: url("$sysCacheClientPathRAD_BTN_ON.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:checked:hover {
	image: url("$sysCacheClientPathRAD_BTN_ON_FOC.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:checked:focus {
	image: url("$sysCacheClientPathRAD_BTN_ON_FOC.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:checked:pressed {
	image: url("$sysCacheClientPathRAD_BTN_ON.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:checked:disabled {
	image: url("$sysCacheClientPathRAD_BTN_ON_DES.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:indeterminate:hover {
	image: url("$sysCacheClientPathRAD_BTN_OFF_FOC.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

QRadioButton::indicator:indeterminate:pressed {
	image: url("$sysCacheClientPathRAD_BTN_OFF.png");
	width: $radiobutton-icono-size;
	height: $radiobutton-icono-size;
}

/*--------------------------------------------------------------------------------
QScrollBar - Barra de scroll vertical y horizontal
--------------------------------------------------------------------------------*/

QScrollBar:vertical {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-borde-color-normal;
	border-radius: $scrollbar-borde-radius;
	padding-left: $scrollbar-padding;
	padding-right: $scrollbar-padding;
	margin: 0px 0px 0px 0px;
	width: $scrollbar-ancho;
}

QScrollBar:horizontal {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-borde-color-normal;
	border-radius: $scrollbar-borde-radius;
	padding-bottom: $scrollbar-padding;
	padding-top: $scrollbar-padding;
	margin: 0px 0px 0px 0px;
	height: $scrollbar-ancho;
}

/* Manejador de la barra de scroll */

QScrollBar::handle:vertical {
	background: $scrollbar-handle-fondo-color;
	border: $borde-size solid $scrollbar-handle-borde-color;
	border-radius: $scrollbar-handle-borde-radius;
	min-height: $scrollbar-handle-ancho;
}

QScrollBar::handle:horizontal {
	background: $scrollbar-handle-fondo-color;
	border: $borde-size solid $scrollbar-handle-borde-color;
	border-radius: $scrollbar-handle-borde-radius;
	min-width: $scrollbar-handle-ancho;
}

QScrollBar::hover {
	background: $scrollbar-fondo-color-hover;
	border: $borde-size solid $scrollbar-borde-color-hover;
}

QScrollBar::handle:hover {
	background: $scrollbar-handle-fondo-color-hover;
	border: $borde-size solid $scrollbar-handle-borde-color-hover;
}

/* Botones en los extremos de la barra de scroll */

QScrollBar::add-line:vertical {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-fondo-color-normal;
	height: $ancho-borde-sin;
	subcontrol-origin: margin;
	subcontrol-position: bottom;
	width: $ancho-borde-sin;
}

QScrollBar::add-line:horizontal {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-fondo-color-normal;
	height: $ancho-minimo;
	subcontrol-origin: margin;
	subcontrol-position: right;
	width: $ancho-minimo;
}

QScrollBar::sub-line:vertical {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-fondo-color-normal;
	height: $ancho-borde-sin;
	subcontrol-position: top;
	subcontrol-origin: margin;
	width: $ancho-borde-sin;
}

QScrollBar::sub-line:horizontal {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-fondo-color-normal;
	height: $ancho-minimo;
	subcontrol-origin: margin;
	subcontrol-position: left;
	width: $ancho-minimo;
}

/* Recuadro de intersección entre las scrollbar horizontal y vertical */

QAbstractScrollArea::corner {
	background: transparent;
	border: transparent;
}

/*--------------------------------------------------------------------------------
QSlider - Deslizador
--------------------------------------------------------------------------------*/

QSlider {
	background: transparent;
	border: $slider-borde-size solid $slider-borde-color;
	border-radius: $slider-borde-radius;
	height: $slider-alto;
	width: $slider-ancho;
}

QSlider::groove:horizontal {
	background-color: $slider-groove-fondo-color;
	border-radius: $slider-groove-borde-radius;
	height: $slider-groove-alto;
}

QSlider::groove:vertical {
	background-color: $slider-groove-fondo-color;
	border-radius: $slider-groove-borde-radius;
	width: $slider-groove-ancho;
}

QSlider::handle:horizontal {
	background-color: $slider-handle-fondo-color;
	border: $slider-handle-borde-size solid $slider-handle-borde-color;
	border-radius: $slider-handle-borde-radius;
	height: $slider-handle-alto;
	margin: $slider-handle-margen 0;
	width: $slider-handle-ancho;
}

QSlider::handle:horizontal:hover {
	background-color: $slider-handle-fondo-color-hover;
	border: $slider-handle-borde-size solid $slider-handle-borde-color-hover;
}

QSlider::handle:vertical {
	background-color: $slider-handle-fondo-color;
	border: $slider-handle-borde-size solid $slider-handle-borde-color;
	border-radius: $slider-handle-borde-radius;
	height: $slider-handle-ancho;
	margin: 0 $slider-handle-margen;
	width: $slider-handle-alto;
}

QSlider::handle:vertical:hover {
	background-color: $slider-handle-fondo-color-hover;
	border: $slider-handle-borde-size solid $slider-handle-borde-color-hover;
}

/*--------------------------------------------------------------------------------
QSplitter - Separador móvil
--------------------------------------------------------------------------------*/

QSplitter {
	background-color: $splitter-fondo-color;
	border: $splitter-borde-size solid $splitter-borde-color;
	border-radius: $splitter-borde-radius;
	width: $splitter-ancho;
}

QSplitter::handle {
	background-color: $splitter-handle-fondo-color;
	border: $splitter-handle-borde-size solid $splitter-handle-borde-color;
	border-radius: $splitter-handle-borde-radius;
	height: $splitter-handle-alto;
	width: $splitter-handle-ancho;
}

QSplitter::handle:horizontal {
	width: $splitter-handle-ancho;
}

QSplitter::handle:vertical {
	height: $splitter-handle-alto;
}

/*--------------------------------------------------------------------------------
QStatusBar - Barra de estado
--------------------------------------------------------------------------------*/

QStatusBar {
	background-color: $statusbar-fondo-color;
	border-top: $statusbar-borde-size solid $statusbar-borde-color;
	color: $statusbar-texto-color;
	height: $statusbar-alto;
}

/*--------------------------------------------------------------------------------
QHeaderView - Cabecera de rejillas y árboles
QTableView - Detalle de la rejilla
VCFootView - Pie de la rejilla
--------------------------------------------------------------------------------*/

QTableView {
	alternate-background-color: $rejilla-fila-fondo-color;
	background-color: $rejilla-fila-fondo-color;
	border: none;
	color: $rejilla-texto-color-detalle;
	font-weight: normal;
	gridline-color: $rejilla-fila-fondo-color;
	qproperty-showGrid: $rejilla-grid;
	selection-background-color: $rejilla-fila-fondo-color-focus;
	selection-color: $rejilla-texto-color-fila-focus;
}

QTableView::item {
	border: none;
	margin-left: $rejilla-celda-margen-izquierdo;
	margin-right: $rejilla-celda-margen-derecho;
}

QTableView QFrame {
	background-color: $rejilla-fila-fondo-color;
}

QTableView QTableCornerButton::section {
	background-color: $rejilla-cabecera-fondo-color;
	border: none;
	border-bottom: $rejilla-cabecera-borde-size solid $rejilla-cabecera-borde-color;
}

QHeaderView {
	background-color: $rejilla-cabecera-fondo-color;
	border: none;
	border-bottom: $rejilla-cabecera-borde-size solid $rejilla-cabecera-borde-color;
}

QHeaderView::section {
	background-color: $rejilla-cabecera-fondo-color;
	border: none;
	color: $rejilla-cabecera-texto-color;
	font-size: $rejilla-cabecera-texto-size;
	font-weight: $rejilla-cabecera-texto-ancho;
	padding-left: $rejilla-cabecera-padding-izquierdo;
	padding-right: $rejilla-cabecera-padding-derecho;
}

QHeaderView::section:horizontal {
	border: none;
	margin-left: $rejilla-celda-margen-izquierdo;
	margin-right: $rejilla-celda-margen-derecho;
}

QHeaderView::section:vertical {
	background-color: $rejilla-cabecera-fondo-color;
	border: none;
	border-bottom: $rejilla-cabecera-borde-size solid $rejilla-cabecera-borde-color;
}

QHeaderView::down-arrow,
QHeaderView::up-arrow {
	margin-left: -24px;
	height: 16px;
	width: 16px;
	subcontrol-position: top right;
	subcontrol-origin: padding;
}

QHeaderView::down-arrow {
	image: url($sysCacheClientPath/ABA.png);
}

QHeaderView::up-arrow {
	image: url($sysCacheClientPath/ARR.png);
}

QHeaderView::section:horizontal:uncheked {
	padding-right: $rejilla-cabecera-horizontal-padding;
}

QHeaderView::section:horizontal:checked {
	padding-right: $rejilla-cabecera-horizontal-checked-padding;
}

VCFootView {
	background-color: $rejilla-pie-fondo-color;
	border: none;
	border-top: $rejilla-cabecera-borde-size solid $rejilla-cabecera-borde-color;
	color: $rejilla-pie-texto-color;
	font-size: $rejilla-pie-texto-size;
	font-weight: $rejilla-pie-texto-ancho;
}

VCFootView::section {
	background-color: $rejilla-pie-fondo-color;
	border: none;
	color: $rejilla-pie-texto-color;
	font-size: $rejilla-pie-texto-size;
	font-weight: $rejilla-pie-texto-ancho;
	padding-right: $rejilla-pie-padding-derecho;
}

/*--------------------------------------------------------------------------------
QTabWidget - Separador de formularios mediante pestañas
--------------------------------------------------------------------------------*/

QTabWidget {
	qproperty-iconSize: $icono-size-sin;
}

QTabWidget::pane {
	border-top: $ancho-borde solid $control-borde-color-linea;
	margin: $margen-sin;
	top: 10px;
}

QTabWidget::tab-bar {
	left: 1px;
	min-width: 10px;
	right: 10px;
	top: 10px;
}

QTabBar {
	font-weight: normal;
	font-size: $fuente-size-s;
	text-transform: none;
}

QTabBar::tab {
	background-color: $formulario-fondo-color;
	border-bottom: $borde-size-seleccionado solid $tab-borde-color-defecto;
	color: $tab-texto-color;
	padding-left: 9px;
	padding-right: 9px;
	padding-bottom: 3px;
	padding-top: 3px;
}

QTabBar::tab:hover {
	border-bottom: $borde-size-seleccionado solid $tab-borde-color-hover;
}

QTabBar::tab:selected {
	color: $tab-texto-color-seleccionado;
	border-bottom: $borde-size-seleccionado solid $tab-borde-color-seleccionada;
}

QTabBar::close-button {
	image: url($sysCacheClientPath/CRR.png);
	margin: 3px;
}

QTabBar::scroller {
	padding-top: 10px;
	width: 64px;
}

QTabBar QToolButton {
	background-color: $formulario-fondo-color;
	border: none;
	border-radius: 0px;
	margin: 0px;
	margin-top: -6px;
	max-height: 16px;
	padding: 0px;
	width: 16px;
}

QTabBar QToolButton:disabled {
	background-color: $control-fondo-color-disabled;
	border: none;
}

QTabBar QToolButton:hover,
QTabBar QToolButton:focus,
QTabBar QToolButton:pressed {
	background-color: $formulario-fondo-color;
	border: none;
}

QTabBar QToolButton::left-arrow {
	image: url($sysCacheClientPath/IZQ.png);
	max-height: 16px;
	width: 16px;
}

QTabBar QToolButton::right-arrow {
	image: url($sysCacheClientPath/DER.png);
	max-height: 16px;
	width: 16px;
}

/*--------------------------------------------------------------------------------
QTextEdit - Caja de edición de texto multilínea
--------------------------------------------------------------------------------*/

QTextEdit {
	background-color: $textedit-fondo-color;
	border-color: $textedit-borde-color;
	border-style: $textedit-borde-style;
	border-width: $textedit-borde-width;
	border-radius: $textedit-borde-radius;
	color: $textedit-texto-color;
	font-size: $textedit-fuente-size;
	padding: $textedit-padding;
	selection-background-color: $textedit-seleccion-fondo-color;
	selection-color: $textedit-seleccion-texto-color;
}

QTextEdit[readOnly="true"] {
	border: none;
}

QTextEdit:hover {
	border-color: $textedit-borde-color-hover;
	border-width: $textedit-borde-width-hover;
}

QTextEdit:focus {
	border-color: $textedit-borde-color-focus;
	border-width: $textedit-borde-width-focus;
}

QTextEdit:disabled {
	background-color: $textedit-fondo-color-disabled;
	border-color: $textedit-borde-color-disabled;
	border-width: $textedit-borde-width-disabled;
	color: $textedit-texto-color-disabled;
}

