/*--------------------------------------------------------------------------------
VSwitch - Interruptor
--------------------------------------------------------------------------------*/

VSwitch {
	max-height: $switch-alto;
	min-height: $switch-alto;
	max-width: $switch-ancho;
	min-width: $switch-ancho;

	/* Fondo: Off, Normal */
	qproperty-backgroundColorOff: $switch-fondo-color-off;
	qproperty-borderColorOff: $switch-borde-color-off;
	qproperty-borderSizeOff: $switch-borde-size-off;

	/* Botón: Off, Normal */
	qproperty-buttonColorOff: $switch-boton-fondo-color-off;
	qproperty-buttonBorderColorOff: $switch-boton-borde-color-off;
	qproperty-buttonBorderSizeOff: $switch-boton-borde-size-off;

	/* Fondo: On, Normal */
	qproperty-backgroundColorOn: $switch-fondo-color-on;
	qproperty-borderColorOn: $switch-borde-color-on;
	qproperty-borderSizeOn: $switch-borde-size-on;

	/* Botón: On, Normal */
	qproperty-buttonColorOn: $switch-boton-fondo-color-on;
	qproperty-buttonBorderColorOn: $switch-boton-borde-color-on;
	qproperty-buttonBorderSizeOn: $switch-boton-borde-size-on;

	/* Fondo: Off, Focus */
	qproperty-backgroundColorOffFocus: $switch-fondo-color-off-focus;
	qproperty-borderColorOffFocus: $switch-borde-color-off-focus;
	qproperty-borderSizeOffFocus: $switch-borde-size-off-focus;

	/* Botón: Off, Focus */
	qproperty-buttonColorOffFocus: $switch-boton-fondo-color-off-focus;
	qproperty-buttonBorderColorOffFocus: $switch-boton-borde-color-off-focus;
	qproperty-buttonBorderSizeOffFocus: $switch-boton-borde-size-off-focus;

	/* Fondo: On, Focus */
	qproperty-backgroundColorOnFocus: $switch-fondo-color-on-focus;
	qproperty-borderColorOnFocus: $switch-borde-color-on-focus;
	qproperty-borderSizeOnFocus: $switch-borde-size-on-focus;

	/* Botón: On, Focus */
	qproperty-buttonColorOnFocus: $switch-boton-fondo-color-on-focus;
	qproperty-buttonBorderColorOnFocus: $switch-boton-borde-color-on-focus;
	qproperty-buttonBorderSizeOnFocus: $switch-boton-borde-size-on-focus;

	/* Fondo: Off, Hover */
	qproperty-backgroundColorOffHover: $switch-fondo-color-off-hover;
	qproperty-borderColorOffHover: $switch-borde-color-off-hover;
	qproperty-borderSizeOffHover: $switch-borde-size-off-hover;

	/* Botón: Off, Hover */
	qproperty-buttonColorOffHover: $switch-boton-fondo-color-off-hover;
	qproperty-buttonBorderColorOffHover: $switch-boton-borde-color-off-hover;
	qproperty-buttonBorderSizeOffHover: $switch-boton-borde-size-off-hover;

	/* Fondo: On, Hover */
	qproperty-backgroundColorOnHover: $switch-fondo-color-on-hover;
	qproperty-borderColorOnHover: $switch-borde-color-on-hover;
	qproperty-borderSizeOnHover: $switch-borde-size-on-hover;

	/* Botón: On, Hover */
	qproperty-buttonColorOnHover: $switch-boton-fondo-color-on-hover;
	qproperty-buttonBorderColorOnHover: $switch-boton-borde-color-on-hover;
	qproperty-buttonBorderSizeOnHover: $switch-boton-borde-size-on-hover;

	/* Fondo: Off, Disabled */
	qproperty-backgroundColorOffDisabled: $switch-fondo-color-off-disabled;
	qproperty-borderColorOffDisabled: $switch-borde-color-off-disabled;
	qproperty-borderSizeOffDisabled: $switch-borde-size-off-disabled;

	/* Botón: Off, Disabled */
	qproperty-buttonColorOffDisabled: $switch-fondo-color-off-disabled;
	qproperty-buttonBorderColorOffDisabled: $switch-boton-borde-color-off-disabled;
	qproperty-buttonBorderSizeOffDisabled: $switch-boton-borde-size-off-disabled;

	/* Fondo: On, Disabled */
	qproperty-backgroundColorOnDisabled: $switch-fondo-color-on-disabled;
	qproperty-borderColorOnDisabled: $switch-borde-color-on-disabled;
	qproperty-borderSizeOnDisabled: $switch-borde-size-on-disabled;

	/* Botón: On, Disabled */
	qproperty-buttonColorOnDisabled: $switch-boton-fondo-color-on-disabled;
	qproperty-buttonBorderColorOnDisabled: $switch-boton-borde-color-on-disabled;
	qproperty-buttonBorderSizeOnDisabled: $switch-boton-borde-size-on-disabled;
}

