/*--------------------------------------------------------------------------------
QDialog - Ventana en cuadro de diálogo
--------------------------------------------------------------------------------*/

QDialog {
	background: $dialog-fondo-color;
	border: $dialog-borde-size solid $dialog-borde-color;
}

/*--------------------------------------------------------------------------------
QDockWidget - Dock
--------------------------------------------------------------------------------*/

QDockWidget {
	background: $dock-fondo-color;
	color: $dock-color;
	font-size: $dock-fuente-size;
	qproperty-titleBarVisible: $dock-titulo-visible;
}

/* Título del dock (no auto-ocultable) */
QDockWidget::title {
	background: $dock-fondo-color;
	color: $dock-texto-color;
	font-size: $dock-titulo-fuente-size;
	margin: 0px;
	padding: 0px;
	text-align: left;
}

/* Título del dock (auto-ocultable) */
QDockWidget QWidget::title {
	background: $dock-fondo-color;
	color: $dock-texto-color;
	font-size: $dock-titulo-fuente-size;
}

/* Botones de la barra de título del dock (auto-ocultable) */
QDockWidget QWidget#title QToolButton#autohide,
QDockWidget QWidget#title QToolButton#close,
QDockWidget QWidget#title QToolButton#float {
	background-color: $dock-titulo-boton-fondo;
	border: $dock-titulo-boton-borde-size solid $dock-titulo-boton-borde-color;
	qproperty-iconSize: $dock-titulo-boton-icono-size;
}

/* Botones de la barra de título del dock (no auto-ocultable) */
QDockWidget::close-button,
QDockWidget::float-button {
	background-color: $dock-titulo-boton-fondo;
	image: none;
	position: absolute;
	subcontrol-origin: margin;
	subcontrol-position: top right;
	top: 0px;
	left: 0px;
	bottom: 0px;
	width: 0px;
}

/*--------------------------------------------------------------------------------
QGroupBox - Caja de grupo
--------------------------------------------------------------------------------*/

QGroupBox {
	background-color: $caja-fondo-color;
	border: $borde-size solid $control-borde-color;
	border-radius: $caja-borde-radius;
	color: $caja-titulo-color;
	font-size: $caja-fuente-size;
	font-weight: $caja-fuente-peso;
	margin-top: $caja-margen-top;
	padding: $caja-padding;
}

QGroupBox::title {
	color: $caja-titulo-color;
	padding-top: $caja-titulo-padding-top;
	padding-left: $caja-titulo-padding-izquierdo;
	subcontrol-origin: margin;
}

QGroupBox#CAJ_FLT {
	background-color: $caja-filtro-fondo-color;
	border: $caja-filtro-borde-size solid $caja-filtro-borde-color;
	border-radius: $caja-filtro-borde-radius;
	min-height: $caja-filtro-alto;
}

/* BOTÓN FILTRO Y LIMPIAR FILTRO */
QGroupBox#CAJ_FLT QPushButton#BTN_ACE {
	min-width: $boton-filtro-ancho;
}

QGroupBox#CAJ_FLT QPushButton#BTN_FLT_LIM {
	background-color: $boton-filtro-limpiar-fondo-color;
	min-width: $boton-filtro-limpiar-ancho;
}

/*--------------------------------------------------------------------------------
QLabel - Etiqueta de texto
--------------------------------------------------------------------------------*/

QLabel {
	background-color: $label-fondo-color;
	color: $label-color;
	margin: 0px;
	margin-right: $control-padding-derecha;
	padding: 0px;
}

/* Títulos de los formularios y menús */

QLabel#TXT_TIT {
	color: $label-titulo-color;
	font-size: $label-titulo-fuente-size;
	font-weight: $label-titulo-peso;
}

/*--------------------------------------------------------------------------------
QLineEdit - Caja de edición de texto en una línea
--------------------------------------------------------------------------------*/

QLineEdit {
	background-color: $control-fondo-color;
	border-color: $control-borde-color;
	border-style: $control-borde-style;
	border-width: $control-borde-width;
	border-radius: $control-borde-radius;
	color: $control-texto-color-edicion;
	font-size: $control-fuente-size;
	height: $control-alto;
	padding-left: $lineedit-padding-izquierda;
	selection-background-color: $control-fondo-texto-color-seleccionado;
	selection-color: $control-texto-color-seleccionado;
}

QLineEdit[readOnly="true"] {
	border: none;
}

QLineEdit:hover {
	border-color: $control-borde-color-hover;
	border-width: $control-borde-width-hover;
}

QLineEdit:focus {
	border-color: $control-borde-color-focus;
	border-width: $control-borde-width-focus;
	padding-left: $lineedit-padding-izquierda-resaltado;
}

QLineEdit:disabled {
	background-color: $control-fondo-color-disabled;
	border-color: $control-borde-color-disabled;
	border-width: $control-borde-width-disabled;
	color: $control-texto-color;
}

/* Textos a buscar en menús */

QLineEdit#TXT_BUS {
	qproperty-placeholderText: 'Texto a buscar';
}

/* Formular alta contacto: nombre fiscal y nombre */

QLineEdit#NAME_CON {
	qproperty-placeholderText: 'Nombre contacto';
	qproperty-text: 'Nombre contacto';
}

