/*--------------------------------------------------------------------------------
QScrollBar - Barra de scroll vertical y horizontal
--------------------------------------------------------------------------------*/

QScrollBar:vertical {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-borde-color-normal;
	border-radius: $scrollbar-borde-radius;
	padding-left: $scrollbar-padding;
	padding-right: $scrollbar-padding;
	margin: 0px 0px 0px 0px;
	width: $scrollbar-ancho;
}

QScrollBar:horizontal {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-borde-color-normal;
	border-radius: $scrollbar-borde-radius;
	padding-bottom: $scrollbar-padding;
	padding-top: $scrollbar-padding;
	margin: 0px 0px 0px 0px;
	height: $scrollbar-ancho;
}

/* Manejador de la barra de scroll */

QScrollBar::handle:vertical {
	background: $scrollbar-handle-fondo-color;
	border: $borde-size solid $scrollbar-handle-borde-color;
	border-radius: $scrollbar-handle-borde-radius;
	min-height: $scrollbar-handle-ancho;
}

QScrollBar::handle:horizontal {
	background: $scrollbar-handle-fondo-color;
	border: $borde-size solid $scrollbar-handle-borde-color;
	border-radius: $scrollbar-handle-borde-radius;
	min-width: $scrollbar-handle-ancho;
}

QScrollBar::hover {
	background: $scrollbar-fondo-color-hover;
	border: $borde-size solid $scrollbar-borde-color-hover;
}

QScrollBar::handle:hover {
	background: $scrollbar-handle-fondo-color-hover;
	border: $borde-size solid $scrollbar-handle-borde-color-hover;
}

/* Botones en los extremos de la barra de scroll */

QScrollBar::add-line:vertical {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-fondo-color-normal;
	height: $ancho-borde-sin;
	subcontrol-origin: margin;
	subcontrol-position: bottom;
	width: $ancho-borde-sin;
}

QScrollBar::add-line:horizontal {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-fondo-color-normal;
	height: $ancho-minimo;
	subcontrol-origin: margin;
	subcontrol-position: right;
	width: $ancho-minimo;
}

QScrollBar::sub-line:vertical {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-fondo-color-normal;
	height: $ancho-borde-sin;
	subcontrol-position: top;
	subcontrol-origin: margin;
	width: $ancho-borde-sin;
}

QScrollBar::sub-line:horizontal {
	background: $scrollbar-fondo-color-normal;
	border: $borde-size solid $scrollbar-fondo-color-normal;
	height: $ancho-minimo;
	subcontrol-origin: margin;
	subcontrol-position: left;
	width: $ancho-minimo;
}

/* Recuadro de intersección entre las scrollbar horizontal y vertical */

QAbstractScrollArea::corner {
	background: transparent;
	border: transparent;
}

/*--------------------------------------------------------------------------------
QSlider - Deslizador
--------------------------------------------------------------------------------*/

QSlider {
	background: transparent;
	border: $slider-borde-size solid $slider-borde-color;
	border-radius: $slider-borde-radius;
	height: $slider-alto;
	width: $slider-ancho;
}

QSlider::groove:horizontal {
	background-color: $slider-groove-fondo-color;
	border-radius: $slider-groove-borde-radius;
	height: $slider-groove-alto;
}

QSlider::groove:vertical {
	background-color: $slider-groove-fondo-color;
	border-radius: $slider-groove-borde-radius;
	width: $slider-groove-ancho;
}

QSlider::handle:horizontal {
	background-color: $slider-handle-fondo-color;
	border: $slider-handle-borde-size solid $slider-handle-borde-color;
	border-radius: $slider-handle-borde-radius;
	height: $slider-handle-alto;
	margin: $slider-handle-margen 0;
	width: $slider-handle-ancho;
}

QSlider::handle:horizontal:hover {
	background-color: $slider-handle-fondo-color-hover;
	border: $slider-handle-borde-size solid $slider-handle-borde-color-hover;
}

QSlider::handle:vertical {
	background-color: $slider-handle-fondo-color;
	border: $slider-handle-borde-size solid $slider-handle-borde-color;
	border-radius: $slider-handle-borde-radius;
	height: $slider-handle-ancho;
	margin: 0 $slider-handle-margen;
	width: $slider-handle-alto;
}

QSlider::handle:vertical:hover {
	background-color: $slider-handle-fondo-color-hover;
	border: $slider-handle-borde-size solid $slider-handle-borde-color-hover;
}

/*--------------------------------------------------------------------------------
QSplitter - Separador móvil
--------------------------------------------------------------------------------*/

QSplitter {
	background-color: $splitter-fondo-color;
	border: $splitter-borde-size solid $splitter-borde-color;
	border-radius: $splitter-borde-radius;
	width: $splitter-ancho;
}

QSplitter::handle {
	background-color: $splitter-handle-fondo-color;
	border: $splitter-handle-borde-size solid $splitter-handle-borde-color;
	border-radius: $splitter-handle-borde-radius;
	height: $splitter-handle-alto;
	width: $splitter-handle-ancho;
}

QSplitter::handle:horizontal {
	width: $splitter-handle-ancho;
}

QSplitter::handle:vertical {
	height: $splitter-handle-alto;
}

/*--------------------------------------------------------------------------------
QStatusBar - Barra de estado
--------------------------------------------------------------------------------*/

QStatusBar {
	background-color: $statusbar-fondo-color;
	border-top: $statusbar-borde-size solid $statusbar-borde-color;
	color: $statusbar-texto-color;
	height: $statusbar-alto;
}

/*--------------------------------------------------------------------------------
QHeaderView - Cabecera de rejillas y árboles
QTableView - Detalle de la rejilla
VCFootView - Pie de la rejilla
--------------------------------------------------------------------------------*/

QTableView {
	alternate-background-color: $rejilla-fila-fondo-color;
