}

QTableView::item {
	border: none;
	margin-left: $rejilla-celda-margen-izquierdo;
	margin-right: $rejilla-celda-margen-derecho;
}

QTableView QFrame {
	background-color: $rejilla-fila-fondo-color;
}

QTableView QTableCornerButton::section {
	background-color: $rejilla-cabecera-fondo-color;
	border: none;
	border-bottom: $rejilla-cabecera-borde-size solid $rejilla-cabecera-borde-color;
}

QHeaderView {
	background-color: $rejilla-cabecera-fondo-color;
	border: none;
	border-bottom: $rejilla-cabecera-borde-size solid $rejilla-cabecera-borde-color;
}

QHeaderView::section {
	background-color: $rejilla-cabecera-fondo-color;
	border: none;
	color: $rejilla-cabecera-texto-color;
	font-size: $rejilla-cabecera-texto-size;
	font-weight: $rejilla-cabecera-texto-ancho;
	padding-left: $rejilla-cabecera-padding-izquierdo;
	padding-right: $rejilla-cabecera-padding-derecho;
}

QHeaderView::section:horizontal {
	border: none;
	margin-left: $rejilla-celda-margen-izquierdo;
	margin-right: $rejilla-celda-margen-derecho;
}

QHeaderView::section:vertical {
	background-color: $rejilla-cabecera-fondo-color;
	border: none;
	border-bottom: $rejilla-cabecera-borde-size solid $rejilla-cabecera-borde-color;
}

QHeaderView::down-arrow,
QHeaderView::up-arrow {
	margin-left: -24px;
	height: 16px;
	width: 16px;
	subcontrol-position: top right;
	subcontrol-origin: padding;
}

QHeaderView::down-arrow {
	image: url($sysCacheClientPath/ABA.png);
}

QHeaderView::up-arrow {
	image: url($sysCacheClientPath/ARR.png);
}

QHeaderView::section:horizontal:uncheked {
	padding-right: $rejilla-cabecera-horizontal-padding;
}

QHeaderView::section:horizontal:checked {
	padding-right: $rejilla-cabecera-horizontal-checked-padding;
}

VCFootView {
	background-color: $rejilla-pie-fondo-color;
	border: none;
	border-top: $rejilla-cabecera-borde-size solid $rejilla-cabecera-borde-color;
	color: $rejilla-pie-texto-color;
	font-size: $rejilla-pie-texto-size;
	font-weight: $rejilla-pie-texto-ancho;
}

VCFootView::section {
	background-color: $rejilla-pie-fondo-color;
	border: none;
	color: $rejilla-pie-texto-color;
	font-size: $rejilla-pie-texto-size;
	font-weight: $rejilla-pie-texto-ancho;
	padding-right: $rejilla-pie-padding-derecho;
}

