--------------------------------------------------------------------------------*/

QTabWidget {
	qproperty-iconSize: $icono-size-sin;
}

QTabWidget::pane {
	border-top: $ancho-borde solid $control-borde-color-linea;
	margin: $margen-sin;
	top: 10px;
}

QTabWidget::tab-bar {
	left: 1px;
	min-width: 10px;
	right: 10px;
	top: 10px;
}

QTabBar {
	font-weight: normal;
	font-size: $fuente-size-s;
	text-transform: none;
}

QTabBar::tab {
	background-color: $formulario-fondo-color;
	border-bottom: $borde-size-seleccionado solid $tab-borde-color-defecto;
	color: $tab-texto-color;
	padding-left: 9px;
	padding-right: 9px;
	padding-bottom: 3px;
	padding-top: 3px;
}

QTabBar::tab:hover {
	border-bottom: $borde-size-seleccionado solid $tab-borde-color-hover;
}

QTabBar::tab:selected {
	color: $tab-texto-color-seleccionado;
	border-bottom: $borde-size-seleccionado solid $tab-borde-color-seleccionada;
}

QTabBar::close-button {
	image: url($sysCacheClientPath/CRR.png);
	margin: 3px;
}

QTabBar::scroller {
	padding-top: 10px;
	width: 64px;
}

QTabBar QToolButton {
	background-color: $formulario-fondo-color;
	border: none;
	border-radius: 0px;
	margin: 0px;
	margin-top: -6px;
	max-height: 16px;
	padding: 0px;
	width: 16px;
}

QTabBar QToolButton:disabled {
	background-color: $control-fondo-color-disabled;
	border: none;
}

QTabBar QToolButton:hover,
QTabBar QToolButton:focus,
QTabBar QToolButton:pressed {
	background-color: $formulario-fondo-color;
	border: none;
}

QTabBar QToolButton::left-arrow {
	image: url($sysCacheClientPath/IZQ.png);
	max-height: 16px;
	width: 16px;
}

QTabBar QToolButton::right-arrow {
	image: url($sysCacheClientPath/DER.png);
	max-height: 16px;
	width: 16px;
}

/*--------------------------------------------------------------------------------
QTextEdit - Caja de edición de texto multilínea
--------------------------------------------------------------------------------*/

QTextEdit {
	background-color: $textedit-fondo-color;
	border-color: $textedit-borde-color;
	border-style: $textedit-borde-style;
	border-width: $textedit-borde-width;
	border-radius: $textedit-borde-radius;
	color: $textedit-texto-color;
	font-size: $textedit-fuente-size;
	padding: $textedit-padding;
	selection-background-color: $textedit-seleccion-fondo-color;
	selection-color: $textedit-seleccion-texto-color;
}

QTextEdit[readOnly="true"] {
	border: none;
}

QTextEdit:hover {
	border-color: $textedit-borde-color-hover;
	border-width: $textedit-borde-width-hover;
}

QTextEdit:focus {
	border-color: $textedit-borde-color-focus;
	border-width: $textedit-borde-width-focus;
}

QTextEdit:disabled {
	background-color: $textedit-fondo-color-disabled;
	border-color: $textedit-borde-color-disabled;
	border-width: $textedit-borde-width-disabled;
	color: $textedit-texto-color-disabled;
}

