	/* qproperty-columnAutoWidth */
	/* qproperty-focusRowIndicatorIcon */
	/* qproperty-sortAscendingIcon */
	/* qproperty-sortDescendingIcon */
	/* qproperty-columnFilterToolIcon */
	/* qproperty-columnFilterToolBoldIcon */
	/* qproperty-columnMenuToolIcon */
	/* qproperty-checkBoxOnIcon */
	/* qproperty-checkBoxOffIcon */
	/* qproperty-filterCheckBoxOnIcon */
	/* qproperty-filterCheckBoxOffIcon */
	/* qproperty-editorPopupOkIcon */
	/* qproperty-editorPopupCancelIcon */
