	qproperty-groupColorLevel7: $qtitangrid-agrupamiento-7-fondo-color;
	qproperty-keepGroupLevelExpanded: $qtitangrid-agrupamiento-nivel-expandido;

	/* Pies de agrupamiento */
	qproperty-summaryGroupItemBackgroundColor: $qtitangrid-item-fondo-color-grupo;
