	qproperty-summaryGroupItemBorderSize: $qtitangrid-item-borde-size-grupo;
	/* qproperty-summaryGroupItemBorderStyle */
	qproperty-summaryGroupItemHeight: $qtitangrid-item-grupo-alto;
	qproperty-summaryGroupItemTextColor: $qtitangrid-pie-texto-color;

	/* Pies de rejilla */
	qproperty-summaryItemBackgroundColor: $qtitangrid-item-fondo-color-pie;
	qproperty-summaryItemBorderColor: $qtitangrid-item-borde-color-pie;
	qproperty-summaryItemBorderSize: $qtitangrid-item-borde-size-pie;
	/* qproperty-summaryItemBorderStyle */
	qproperty-summaryItemHeight: $qtitangrid-item-pie-alto;
	qproperty-summaryItemTextColor: $qtitangrid-pie-texto-color;

	/* Línea de columnas inmovilizadas */
	qproperty-fixedSeparatorColor: $qtitangrid-inmovilizadas-borde-color;
