}

/* Botón de menú */

QToolButton {
	background-color: $toolbar-boton-fondo-color;
	border: $borde-size solid $toolbar-boton-icono-borde-color;
	border-radius: $boton-icono-borde-radius;
	color: $label-color;
	font-size: $boton-fuente-size;
	font-weight: $boton-texto-peso;
	margin: $margen-sin;
	min-height: $toolbar-boton-icono-alto;
	min-width: $toolbar-boton-icono-ancho;
	text-align: $boton-texto-alineacion;
	text-transform: $boton-texto-transformacion;
	qproperty-iconSize: $toolbar-boton-icono-size;
}

QToolButton:hover {
	background-color: $toolbar-boton-icono-fondo-color-hover;
	border: $borde-size solid $toolbar-boton-icono-borde-color-hover;
}

QToolButton:focus {
	background-color: $toolbar-boton-icono-fondo-color-focus;
	border: $borde-size-seleccionado solid $boton-icono-borde-color-focus;
}

QToolButton:pressed {
	background-color: $toolbar-boton-icono-fondo-color-pressed;
	border: $borde-size-seleccionado solid $toolbar-boton-icono-borde-color-pressed;
}

QToolButton:disabled {
	background-color: $toolbar-boton-icono-fondo-color-disabled;
	border: $borde-size solid $toolbar-boton-icono-borde-color-disabled;
	color: $toolbar-boton-icono-color-disabled;
}

QToolButton::menu-indicator {
	background-color: transparent;
	color: transparent;
}

/* Botón de menú de controles de edición de maestro */

VAbstractBrowser QToolButton,
VFormulaEditBrowser QToolButton {
	background-color: $toolbar-menu-boton-fondo-color;
	border: $toolbar-menu-boton-borde-size solid $toolbar-menu-boton-borde-color;
	border-radius: $toolbar-menu-boton-borde-radius;
	color: $toolbar-menu-boton-label-color;
	font-size: $boton-fuente-size;
	font-weight: $boton-texto-peso;
	margin: $margen-sin;
	margin-left: $toolbar-menu-boton-margen-izquierdo;
	min-height: $toolbar-menu-boton-icono-alto;
	min-width: $toolbar-menu-boton-icono-ancho;
	margin-top: $toolbar-menu-boton-margen-top;
	text-align: $boton-texto-alineacion;
	text-transform: $boton-texto-transformacion;
	qproperty-iconSize: $toolbar-menu-boton-icono-size;
}

VAbstractBrowser QToolButton:hover,
VFormulaEditBrowser QToolButton:hover {
	background-color: $toolbar-menu-boton-fondo-color-hover;
	border: $toolbar-menu-boton-borde-size solid $toolbar-menu-boton-borde-color-hover;
}

VAbstractBrowser QToolButton:focus,
VFormulaEditBrowser QToolButton:focus {
	background-color: $toolbar-menu-boton-fondo-color-focus;
	border: $toolbar-menu-boton-borde-size-seleccionado solid $toolbar-menu-boton-borde-color-focus;
}

VAbstractBrowser QToolButton:pressed,
VFormulaEditBrowser QToolButton:pressed {
	background-color: $toolbar-menu-boton-fondo-color-pressed;
	border: $toolbar-menu-boton-borde-size-seleccionado solid $toolbar-menu-boton-borde-color-pressed;
}

VAbstractBrowser QToolButton:disabled,
VFormulaEditBrowser QToolButton:disabled {
	background-color: $toolbar-menu-boton-fondo-color-disabled;
	border: $toolbar-menu-boton-borde-size-disabled solid $toolbar-menu-boton-borde-color-disabled;
	color: $toolbar-menu-boton-label-color-disabled;
}

VAbstractBrowser QToolButton::menu-indicator,
VFormulaEditBrowser QToolButton::menu-indicator {
	background-color: $toolbar-menu-boton-indicador-fondo-color;
	color: $toolbar-menu-boton-indicador-texto-color;
}

/* Botón de toolbar de rejilla o dock */

QToolBar[objectName$="_MEN"] {
	background-color: $toolbar-menu-fondo-color;
}

QToolBar QToolButton {
	background-color: $toolbar-rejilla-boton-fondo-color;
	border: $borde-size solid $toolbar-rejilla-boton-borde-color;
	border-radius: $toolbar-rejilla-boton-borde-radius;
	color: $toolbar-rejilla-boton-label-color;
	font-size: $boton-fuente-size;
	font-weight: $boton-texto-peso;
	margin: $margen-sin;
	min-height: $toolbar-rejilla-boton-icono-alto;
	min-width: $toolbar-rejilla-boton-icono-ancho;
	margin-top: $toolbar-rejilla-boton-margin-top;
	margin-right: 6px;
	text-align: $boton-texto-alineacion;
	text-transform: $boton-texto-transformacion;
	qproperty-iconSize: $toolbar-rejilla-boton-icono-size;
}

QToolBar QToolButton[text="Opciones"] {
	background-color: $toolbar-rejilla-boton-fondo-color;
	padding-left: $toolbar-boton-texto-padding-izquierda;
	padding-right: $toolbar-boton-texto-padding-derecha;
}

QToolBar QToolButton:hover {
	background-color: $toolbar-rejilla-boton-fondo-color-hover;
	border: $borde-size solid $toolbar-rejilla-boton-borde-color-hover;
}

QToolBar QToolButton:focus {
	background-color: $toolbar-rejilla-boton-fondo-color-focus;
	border: $toolbar-rejilla-boton-borde-size-seleccionado solid $toolbar-rejilla-boton-borde-color-focus;
}

QToolBar QToolButton:pressed {
	background-color: $toolbar-rejilla-boton-fondo-color-pressed;
	border: $toolbar-rejilla-boton-borde-size-seleccionado solid $toolbar-rejilla-boton-borde-color-pressed;
}

/*--------------------------------------------------------------------------------
QTooltip - Tooltip
--------------------------------------------------------------------------------*/

QToolTip {
	background-color: $tooltip-fondo-color;
	border: $tooltip-borde-size solid $tooltip-borde-color;
	color: $tooltip-texto-color;
	font-size: $tooltip-fuente-size;
	padding: $tooltip-padding;
	vertical-align: center;
}

/*--------------------------------------------------------------------------------
QTreeView - Árbol visor de tablas y menú arbolado
--------------------------------------------------------------------------------*/

QTreeView {
	outline: 0;
	background-color: $formulario-fondo-color;
	color: $treeview-texto-color;
	font-size: $treeview-boton-fuente-size;
	selection-background-color: transparent;
	selection-color: $treeview-texto-color-seleccionado;
	show-decoration-selected: 1;
}

QTreeView QHeaderView {
	min-height: $treeview-cabecera-alto;
}

QTreeView::item {
	margin-bottom: 2px;
	margin-right: 10px;
	margin-top: 1px;
	padding-bottom: 6px;
	padding-top: 6px;
}

QTreeView::item:hover {
	border-color: transparent;
	color: $treeview-texto-color-hover;
}

QTreeView::item:selected {
	color: $treeview-texto-color-seleccionado;
}

QTreeView::branch:closed:has-children:!has-siblings,
QTreeView::branch:closed:has-children:has-siblings {
	image: url($sysCacheClientPath/DER.png);
}

QTreeView::branch:open:has-children:!has-siblings,
QTreeView::branch:open:has-children:has-siblings {
	image: url($sysCacheClientPath/ABA.png);
}

/*--------------------------------------------------------------------------------
VCContenedorNotificaciones - Contenedor de notificaciones
VCNotificacion - Notificación
--------------------------------------------------------------------------------*/

VCContenedorNotificaciones {
	background-color: $notificacion-contenedor-fondo-color;
	border: none;
	margin: 0px;
	padding: 0px;
}

VCContenedorNotificaciones QFrame {
	background-color: $notificacion-contenedor-frame-fondo-color;
	border: none;
}

VCNotificacion {
	background-color: $notificacion-fondo-color;
	border: $notificacion-borde-size solid $notificacion-borde-color;
	border-radius: $notificacion-borde-radius;
	color: $notificacion-texto-color;
	min-height: $notificacion-alto;
	margin-bottom: $notificacion-margen-bottom;
	padding: $notificacion-padding;
}

VCNotificacion QLabel {
	background-color: transparent;
	color: $notificacion-texto-color;
	font-size: $notificacion-fuente-size;
	font-weight: normal;
	min-width: $notificacion-ancho-minimo;
	padding-left: $notificacion-padding-izquierda;
	text-transform: none;
}

VCNotificacion QPushButton {
	background-color: transparent;
	border: none;
}

VCNotificacion QPushButton#close {
	height: $notificacion-cerrar-alto;
	min-width: $notificacion-cerrar-ancho;
	qproperty-iconSize: $notificacion-cerrar-size;
	width: $notificacion-cerrar-ancho;
}

VCNotificacion QPushButton#close:hover {
	background-color: $notificacion-cerrar-hover-fondo-color;
	border: none;
}

VCNotificacion QPushButton#icon {
	max-height: $notificacion-icono-alto;
	max-width: $notificacion-icono-ancho;
	padding: 0px;
	qproperty-iconSize: $notificacion-icono-size;
}

