/*--------------------------------------------------------------------------------
Asistente modificar campo

Controles:
#define OBJ_NAME_SUMMARY "summary" -> Ventana resumen (segunda) -> QFrame
#define OBJ_NAME_TITLE "title" -> Título -> QLabel
#define OBJ_NAME_MAIN "main" -> Ventana principal (primera) -> QFrame
#define OBJ_NAME_REGISTERS "registers" -> Registros -> QLabel y QComboBox
#define OBJ_NAME_TOTAL_REGISTERS "total-registers" -> Total registros -> QLabel y QLineEdit
#define OBJ_NAME_FIELD "field" -> Campo -> QLabel y QComboBox
#define OBJ_NAME_FILTER "filter" -> Filtro -> QLabel y VFormulaEditBrowser
#define OBJ_NAME_NEW_VALUE "new-value" -> Nuevo valor -> QLabel y QComboBox
#define OBJ_NAME_CONSTANT_VALUE "constant-value" -> Valor constante -> QLabel y QLineEdit, VBoundFieldEdit, VDateEdit, VTimeEdit, VDateTimeEdit, VComboBox, QDoubleSpinBox, VImageEdit, VCEditBrowserTexto, VFormulaEditBrowser
#define OBJ_NAME_FORMULE_VALUE "formule-value" -> Valor fórmula -> QLabel y VFormulaEditBrowser
#define OBJ_NAME_CANCEL "cancel" -> Botón cancelar -> QPushButton
#define OBJ_NAME_NEXT "next" -> Botón siguiente -> QPushButton
#define OBJ_NAME_BACK "back" -> Botón atrás -> QPushButton
#define OBJ_NAME_MODIFY "modify" -> Botón modificar -> QPushButton
--------------------------------------------------------------------------------*/

VCModificarCampoDlg {
	background-color: $modificar-campo-fondo-color;
}

VCModificarCampoDlg[cssClass="wizard"]>QFrame {
	padding: 24px;
}

VCModificarCampoDlg QLabel {
	border: none;
	height: 0px;
	margin: 0px;
	margin-top: 12px;
	padding: 0px;
	width: 0;
}

VCModificarCampoDlg QLabel#title,
VCModificarCampoDlg QLabel#summary {
	border: none;
	margin: 0px;
	margin: 0px;
	max-height: 0px;
	max-width: 0px;
	padding: 0px;
}

VCModificarCampoDlg QLabel[cssClass="warning"] {
	color: $modificar-campo-texto-color-error;
	margin-bottom: 6px;
	text-transform: none;
}

